import{_ as b,o as e,c as a,j as p,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"魔法战队下属 冰冻泰坦","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/魔法战队/魔法战队下属 冰冻泰坦.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/魔法战队/魔法战队下属 冰冻泰坦.md"}'),s={name:"4.资源分区/2.改造与功法/改造/4.综合类/魔法战队/魔法战队下属 冰冻泰坦.md"};function _(o,r,d,l,i,c){return e(),a("div",null,[...r[0]||(r[0]=[p("h1",{id:"魔法战队下属-冰冻泰坦",tabindex:"-1"},[t("魔法战队下属 冰冻泰坦 "),p("a",{class:"header-anchor",href:"#魔法战队下属-冰冻泰坦","aria-label":'Permalink to "魔法战队下属 冰冻泰坦"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),n('<h1 id="魔法战队下属-冰冻泰坦-1" tabindex="-1">魔法战队下属 冰冻泰坦 <a class="header-anchor" href="#魔法战队下属-冰冻泰坦-1" aria-label="Permalink to &quot;魔法战队下属 冰冻泰坦&quot;">​</a></h1><p>【魔法战队下属装备】<br> 魔法战队-冰冻泰坦<br> “冰冻泰坦是我少数在物理性质上还原能量攻击所进行的尝试之一。不过，由于低温本身在大部分场合并不算特别实用……这一类型的护甲仍然具有物理攻击的性质。”</p><p>【D级“冰冻泰坦”动力盔甲】</p><p>代号：神盾<br> 分类：重甲<br> 基本属性：盔甲防御4/4，盔甲减值3<br> 特殊属性：无<br> 描述：神盾是一件大型外骨骼动力装甲，其外观以浅蓝色为主，装甲厚重而庞大。神盾装甲携带的巨盾能够有效阻碍目标攻击。<br> 外置装备：【斯巴达之盾】</p><p>【斯巴达之盾】：视为一件盾专业武器，在着装盔甲时会同步被你持有。斯巴达之盾的武器伤害为3L，武器体积4，具有【格挡5】【双手】，伤害类型：物理-钝击。</p><p>你可以消费一个移动动作进行基础规则中的格挡行为，随后在该场景内，你从斯巴达之盾中获得的防御增加1点；当你使用斯巴达之盾攻击并命中目标后，目标需要使用强韧豁免对抗伤害出目，失败则在该场景内只能攻击你，这是一个D级创伤来源的【胁迫】效果。这一效果同样需要你先使用移动动作进行格挡后才能生效。</p><p>代号：镜像<br> 分类：重甲<br> 基本属性：盔甲防御4/4，盔甲减值3<br> 特殊属性：无<br> 描述：镜像是一件大型外骨骼动力装甲，其外观以浅蓝色为主。介于低温在战斗中的非显著效果，镜像配备了纯物理伤害的武装，用于在特定场合下降低战斗压力。<br> 外置装备：【两面神火炮】</p><p>【两面神火炮】：两面神火炮视为一件炮专业武器，使用【敏捷属性+射击+专业：炮+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。两面神火炮的武器伤害为8L，武器体积5，伤害类型：物理-穿刺，具有【高速5】（已计入远程武器自带的高速），【破甲3】【无限子弹】【双手】，速射等级【无】，射程200米。</p><p>两面神火炮在攻击时可以额外选择一个目标（无法选择同一目标）。</p><p>代号：冰甲<br> 分类：轻甲<br> 基本属性：盔甲防御2/2<br> 特殊属性：无<br> 描述：冰是一件大型外骨骼动力装甲，其外观以浅蓝色为主。除了装甲结构外，冰甲减轻了大部分结构以安装低温发射器，用于迅速冻结目标。<br> 外置装备：【低温发射器】</p><p>【低温发射器】：低温发射器视为一件手枪武器，使用【敏捷属性+射击+专业：手枪+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。低温发射器的武器伤害为3L，武器体积2，伤害类型：物理-穿刺，具有【高速5】（已计入远程武器自带的高速），【无限子弹】，速射等级【短点射】，射程30米。</p><p>启动低温发射器需要一个移动动作，随后在该场景内你可以正常使用这一武器进行攻击；低温发射器命中后会使目标承受1点不可豁免的冻结不良点数。</p><p>【C级“冰冻泰坦”动力盔甲】</p><p>代号：神盾<br> 分类：重甲<br> 基本属性：盔甲防御12/12，盔甲减值3<br> 特殊属性：无<br> 描述：神盾是一件大型外骨骼动力装甲，其外观以浅蓝色为主，装甲厚重而庞大。神盾装甲携带的巨盾能够有效阻碍目标攻击。<br> 外置装备：【斯巴达之盾】</p><p>【斯巴达之盾】：视为一件盾专业武器，在着装盔甲时会同步被你持有。斯巴达之盾的武器伤害为3L，武器体积4，具有【格挡13】【双手】，伤害类型：物理-钝击。</p><p>你可以消费一个移动动作进行基础规则中的格挡行为，随后在该场景内，你获得基于格挡防御的【防弹】【防能量武器】特性，你从斯巴达之盾中获得的防御增加1点；随后，你在进行格挡时可以为触及距离内的单一友方目标提供【全遮蔽】效果，持续一轮。</p><p>支付D+1000：斯巴达之盾提供的【全遮蔽】效果可以同时对触及范围内的友方目标生效，购买这一能力如同正常购买了一项D级技艺一样处理，因此会正常提供自由属性。</p><p>代号：镜像<br> 分类：重甲<br> 基本属性：盔甲防御12/12，盔甲减值3<br> 特殊属性：无<br> 描述：镜像是一件大型外骨骼动力装甲，其外观以浅蓝色为主。介于低温在战斗中的非显著效果，镜像配备了纯物理伤害的武装，用于在特定场合下降低战斗压力。<br> 外置装备：【两面神火炮】</p><p>【两面神火炮】：两面神火炮视为一件炮专业武器，使用【敏捷属性+射击+专业：炮+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。两面神火炮的武器伤害为13L，武器体积5，伤害类型：物理-穿刺，具有【高速5】（已计入远程武器自带的高速），【破甲3】【毁灭】【无限子弹】【双手】，速射等级【短点射】，射程200米。</p><p>两面神火炮在攻击时可以额外选择一个目标（无法选择同一目标）。</p><p>代号：冰甲<br> 分类：轻甲<br> 基本属性：盔甲防御10/10<br> 特殊属性：无<br> 描述：冰是一件大型外骨骼动力装甲，其外观以浅蓝色为主。除了装甲结构外，冰甲减轻了大部分结构以安装低温发射器，用于迅速冻结目标。介于低温发生器的波及范围，在提高功率后，冰甲也会被低温影响。<br> 外置装备：【低温发射器】</p><p>【低温发射器】：低温发射器视为一件手枪武器，使用【敏捷属性+射击+专业：手枪+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。低温发射器的武器伤害为11L，武器体积2，伤害类型：物理-穿刺，具有【高速5】（已计入远程武器自带的高速），【无限子弹】，速射等级【连射】，射程30米。</p><p>从现在开始，低温发射器不再需要启动，攻击命中后附带1点不可豁免的冻结不良点数；提高低温发射器的功率需要消费一个花招动作，随后在该场景内，低温发射器附带的冻结不良点数增加1点，同时使自身承受1点不可避免的冻结不良点数，每轮只会承受一次。</p><p>你随时可以使用一个花招动作降低低温发生器的功率，从而失去增加冻结不良点数的效果，也无需继续额外承受相应不良点数（已承受的不良点数正常生效）。</p><p>【B级“冰冻泰坦”动力盔甲】</p><p>代号：神盾<br> 分类：重甲<br> 基本属性：盔甲防御19/19，盔甲减值3<br> 特殊属性：无<br> 描述：神盾是一件大型外骨骼动力装甲，其外观以浅蓝色为主，装甲厚重而庞大。神盾装甲携带的巨盾能够有效阻碍目标攻击。<br> 外置装备：【斯巴达之盾】</p><p>【斯巴达之盾】：视为一件盾专业武器，在着装盔甲时会同步被你持有。斯巴达之盾的武器伤害为3L，武器体积4，具有【格挡20】【双手】，伤害类型：物理-钝击。</p><p>你可以消费一个移动动作进行基础规则中的格挡行为，随后在该场景内，你获得基于格挡防御的【防弹】【防能量武器】特性，与1个基于格挡防御的防御附加成功数；随后，你在进行格挡时，可以为触及距离内的单一友方目标提供【全遮蔽】效果，并具有【强拦截】，持续一轮。</p><p>代号：镜像<br> 分类：重甲<br> 基本属性：盔甲防御19/19，盔甲减值3<br> 特殊属性：无<br> 描述：镜像是一件大型外骨骼动力装甲，其外观以浅蓝色为主。介于低温在战斗中的非显著效果，镜像配备了纯物理伤害的武装，用于在特定场合下降低战斗压力。<br> 外置装备：【两面神火炮】</p><p>【两面神火炮】：两面神火炮视为一件炮专业武器，使用【敏捷属性+射击+专业：炮+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。两面神火炮的武器伤害为20L，武器体积5，伤害类型：物理-穿刺，具有【高速6】（已计入远程武器自带的高速），【破甲6】【湮灭】【无限子弹】【双手】，速射等级【连射】，射程200米。</p><p>两面神火炮在攻击时可以额外选择一个目标（无法选择同一目标），但若你放弃攻击两个目标，则可以在攻击后对出目进行重骰，必须接受第二次结果（每轮只能因此重骰一次）。</p><p>代号：冰甲<br> 分类：轻甲<br> 基本属性：盔甲防御17/17<br> 特殊属性：【防能量武器】<br> 描述：冰是一件大型外骨骼动力装甲，其外观以浅蓝色为主。除了装甲结构外，冰甲减轻了大部分结构以安装低温发射器，用于迅速冻结目标。介于低温发生器的波及范围，在提高功率后，冰甲也会被低温影响，因此该装甲对能量性质的输出应用了对策措施。<br> 外置装备：【低温发射器】</p><p>【低温发射器】：低温发射器视为一件手枪武器，使用【敏捷属性+射击+专业：手枪+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。低温发射器的武器伤害为18L，武器体积2，伤害类型：物理-穿刺，具有【高速5】（已计入远程武器自带的高速），【无限子弹】，速射等级【连射】，射程30米。</p><p>从现在开始，低温发射器不再需要启动，攻击命中后附带2点不可豁免的冻结不良点数；提高低温发射器的功率需要消费一个花招动作，随后在该场景内，低温发射器附带的冻结不良点数增加2点，同时在攻击后会使自身承受1点不可避免的冻结不良点数，每轮只会承受一次。</p><p>你随时可以使用一个花招动作降低低温发生器的功率，从而失去增加冻结不良点数的效果，也无需继续额外承受相应不良点数（已承受的不良点数正常生效）。</p><p>【A级“冰冻泰坦”动力盔甲】</p><p>代号：神盾<br> 分类：重甲<br> 基本属性：盔甲防御28/28，基于盔甲2个防御附加，盔甲减值3<br> 特殊属性：无<br> 描述：神盾是一件大型外骨骼动力装甲，其外观以浅蓝色为主，装甲厚重而庞大。神盾装甲携带的巨盾能够有效阻碍目标攻击。<br> 外置装备：【斯巴达之盾】</p><p>【斯巴达之盾】：视为一件盾专业武器，在着装盔甲时会同步被你持有。斯巴达之盾的武器伤害为3L，武器体积4，具有【格挡30】【双手】，伤害类型：物理-钝击。</p><p>当你持有斯巴达之盾时，你获得基于格挡防御的【防弹】【防能量武器】特性，具有额外2个防御附加成功数（基于格挡防御）；你在进行格挡时，可以为触及距离内的单一友方目标提供【全遮蔽】效果，并具有【强拦截】，持续一轮。</p><p>你可以消费一个杂技动作，随后在当轮内，你可以免疫一次单体攻击，这是一个A级别、环境来源的无敌效果。</p><p>代号：镜像<br> 分类：重甲<br> 基本属性：盔甲防御28/28，基于盔甲2个防御附加，盔甲减值3<br> 特殊属性：无<br> 描述：镜像是一件大型外骨骼动力装甲，其外观以浅蓝色为主。介于低温在战斗中的非显著效果，镜像配备了纯物理伤害的武装，用于在特定场合下降低战斗压力。<br> 外置装备：【两面神火炮】</p><p>【两面神火炮】：两面神火炮视为一件炮专业武器，使用【敏捷属性+射击+专业：炮+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。两面神火炮的武器伤害为20L，武器体积5，伤害类型：物理-穿刺，具有【高速6】（已计入远程武器自带的高速），【破甲6】【湮灭】【无限子弹】【双手】，额外获得2个攻击附加成功数，速射等级【连射】，射程200米。</p><p>每轮开始时，你会额外获得4AP用于使用两面神火炮进行攻击，这种攻击只能附带魔法战队下属技艺，或进行不附带招式的普通攻击；每轮一次，当你的攻击命中后，若对出目不满意则可以进行一次重骰，两者取高处理。</p><p>支付1点核能，两面神火炮提供的额外附加成功数提升至7个，持续一轮。</p><p>代号：冰甲<br> 分类：轻甲<br> 基本属性：盔甲防御26/26<br> 特殊属性：【防能量武器】<br> 描述：冰是一件大型外骨骼动力装甲，其外观以浅蓝色为主。除了装甲结构外，冰甲减轻了大部分结构以安装低温发射器，用于迅速冻结目标。介于低温发生器的波及范围，在提高功率后，冰甲也会被低温影响，因此该装甲对能量性质的输出应用了对策措施。<br> 外置装备：【低温发射器】</p><p>【低温发射器】：低温发射器视为一件手枪武器，使用【敏捷属性+射击+专业：手枪+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。低温发射器的武器伤害为18L，武器体积2，伤害类型：物理-穿刺，具有【高速5】（已计入远程武器自带的高速），【无限子弹】，速射等级【连射】，额外获得2个攻击附加成功数，射程30米。</p><p>从现在开始，低温发射器不再需要启动，攻击命中后附带4点不可豁免的冻结不良点数；提高低温发射器的功率需要消费一个移动动作，随后在该场景内，低温发射器附带的冻结不良点数增加4点，同时在攻击后会使自身承受1点不可避免的冻结不良点数，每轮只会承受一次。</p><p>当你启动了功率提升后，被低温发射器命中的目标需要使用反射豁免对抗伤害出目，失败则陷入A级环境来源的【冰封】状态，该状态持续一轮。</p><p>你随时可以使用一个花招动作降低低温发生器的功率，从而失去增加冻结不良点数的效果，也无需继续额外承受相应不良点数（已承受的不良点数正常生效）。</p><p>【S级“冰冻泰坦”动力盔甲】<br> 待补充。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',52)])])}const L=b(s,[["render",_]]);export{f as __pageData,L as default};
